#include <Windows.h>

int main() {
    HANDLE hFile = CreateFileA("example.txt", GENERIC_READ | GENERIC_WRITE, 0, NULL, OPEN_EXISTING, FILE_ATTRIBUTE_NORMAL, NULL);
    if (hFile == INVALID_HANDLE_VALUE) {
        // Handle error
    }

    if (!LockFile(hFile, 0, 0, 1, 0)) {
        // Handle error
    }

    // Perform operations on the file

    if (!UnlockFile(hFile, 0, 0, 1, 0)) {
        // Handle error
    }

    CloseHandle(hFile);
